<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;class OrderCompletionProof extends Model{use SoftDeletes;protected $fillable=['order_id','dispatch_assignment_id','worker_id','status','proof_type','worker_note','customer_note','admin_note','submitted_at','accepted_at','disputed_at','rejected_at','reviewed_by_customer_id','reviewed_by_admin_id','metadata'];protected function casts():array{return ['submitted_at'=>'datetime','accepted_at'=>'datetime','disputed_at'=>'datetime','rejected_at'=>'datetime','metadata'=>'array'];}public function order(){return $this->belongsTo(Order::class);}public function events(){return $this->hasMany(OrderCompletionProofEvent::class);} }